function saveBase64ToFile(base64String, filePath)
  if base64String == nil or base64String == "" then
      return false
  end
  
  local success, result = pcall(function()
    local cleanBase64 = base64String:match(",[^,]+$") or base64String
    cleanBase64 = cleanBase64:gsub("data:[^;]+;base64,", "")
    
    local decodedBytes = Base64.decode(cleanBase64, Base64.DEFAULT)
    
    if decodedBytes == nil then
    end
    
    local dir = File(filePath).getParentFile()
    if not dir.exists() then
      dir.mkdirs()
    end
    
    local fos = FileOutputStream(File(filePath))
    fos.write(decodedBytes)
    fos.close()
    return true
  end)
  
  if not success then
    return false
  end
  return true
end

function checkAndCreateFiles()
  for filePath, base64Str in pairs(base64Map) do
    local file = File(filePath)
    if not file.exists() then
      local success = saveBase64ToFile(base64Str, filePath)
      if success then
      else
      end
    else
    end
  end
end

function loadImageFromFile(path)
  local file = File(path)
  if file.exists() then
    local options = BitmapFactory.Options()
    options.inPreferredConfig = Bitmap.Config.ARGB_8888
    local bmp = BitmapFactory.decodeFile(path, options)
    if bmp then
      return bmp
    else
    end
  else
  end
  return nil
end

function animateTextColor(view)
  local animator = ObjectAnimator.ofInt(view, "textColor", {
    0xFFE91E63, 0xFF3F51B5, 0xFF4CAF50, 0xFFFFC107
  })
  animator.setEvaluator(ArgbEvaluator())
  animator.setDuration(2000)
  animator.setRepeatCount(ValueAnimator.INFINITE)
  animator.setRepeatMode(ValueAnimator.REVERSE)
  animator.start()
end

function iconButton(imagePath, label, onClick)
  local layout = {
    LinearLayout,
    orientation = "horizontal",
    gravity = "center_vertical",
    layout_width = "match_parent",
    layout_height = "wrap",
    layout_marginTop = "8dp",
    layout_marginBottom = "8dp",
    {
      ImageView,
      id = "iconImg",
      layout_width = "40dp",
      layout_height = "40dp",
      layout_marginRight = "12dp",
      scaleType = "fitCenter"
    },
    {
      TextView,
      id = "btnText",
      text = label,
      clickable = true,
      focusable = true,
      padding = "16dp",
      textSize = "16sp",
      textColor = 0xff6effff,
      layout_width = "0dp",
      layout_weight = 1,
      layout_height = "wrap_content"
    }
  }

  local ids = {}
  local view = loadlayout(layout, ids)

  ids.btnText.onClick = onClick

  thread(function()
    local bmp = loadImageFromFile(imagePath)
    activity.runOnUiThread(function()
      if bmp then
        ids.iconImg.setImageBitmap(bmp)
      else
        ids.iconImg.setBackgroundColor(0xFFEC00FF)
      end
      animateTextColor(ids.btnText)
    end)
  end)
  return view
end

function showLoading()
  activity.runOnUiThread(function()
    local loadingLayout = {
      LinearLayout,
      orientation = "vertical",
      gravity = "center",
      background = "#AA000000",
      layout_width = "match_parent",
      layout_height = "match_parent",
      {
        ProgressBar,
        layout_width = "60dp",
        layout_height = "60dp"
      },
      {
        TextView,
        text = "Loading...",
        textColor = 0xFFFFFFFF,
        textSize = "16sp",
        layout_marginTop = "16dp"
      }
    }
    loadingView = loadlayout(loadingLayout)
    local lp = WindowManagerLayoutParams()
    lp.width = WindowManagerLayoutParams.MATCH_PARENT
    lp.height = WindowManagerLayoutParams.MATCH_PARENT
    lp.format = PixelFormat.TRANSLUCENT
    lp.flags = WindowManagerLayoutParams.FLAG_NOT_FOCUSABLE
    lp.gravity = Gravity.CENTER
    lp.type = (Build.VERSION.SDK_INT >= 26) and 2038 or 2002
    wm.addView(loadingView, lp)
  end)
end

function hideLoading()
  activity.runOnUiThread(function()
    if loadingView then 
      pcall(function() 
        wm.removeView(loadingView) 
        loadingView = nil
      end) 
    end
  end)
end
