      local a = e.getAction()
      if a == MotionEvent.ACTION_DOWN then
        startX = e.getRawX()
        startY = e.getRawY()
        originX = lp.x
        originY = lp.y
      elseif a == MotionEvent.ACTION_MOVE then
        local dx = e.getRawX() - startX
        local dy = e.getRawY() - startY
        lp.x = originX + dx
        lp.y = originY + dy
        wm.updateViewLayout(modView, lp)
      end
      return true
    end)

